+		t.Fatal(err)
+	}
+	f, err := os.Open(path)
+	if err != nil {
+		t.Fatal(err)
+	}
+	defer f.Close()
+
+	// Remove the file at path
+	os.Remove(path)
+
+	// When path is gone, fileRotated returns false (not rotated yet)
+	if fileRotated(f, path) {
+		t.Error("fileRotated should return false when path is gone")
+	}
+}
